parameters.functionCode:
// INTAKE BLOCK: Prepare lead payload
// This function normalizes raw input data into a structured format
// Input: Raw JSON from webhook (name, email, company, message)
// Output: Standardized lead object with metadata

// KEY CONFIGURATIONS:
// - Replace these IDs with your actual workflow/execution IDs
// - Adjust timestamp format if needed
// - Add additional fields based on your form structure

return [
  {
    json: {
      // Unique identifiers for tracking this lead through the workflow
      workflow_id: `lead-${Date.now()}`,
      trace_id: `trace-${$execution.id}`,
      created_at: new Date().toISOString(),

      // Raw input normalized (trimmed, lowercased where appropriate)
      input: {
        name: ($json.name || '').trim(),
        email: ($json.email || '').trim().toLowerCase(),
        company: ($json.company || 'Unknown').trim(),
        message: ($json.message || '').trim()
      },

      // Metadata about the incoming request
      metadata: {
        received_at: new Date().toISOString(),
        source_platform: $json.source_platform || 'web_form',
        user_agent: $json.user_agent || 'unknown',
        request_id: $json.request_id || null
      }
    }
  }
];

// DATA ENRICHMENT & NORMALIZATION
// Merges enriched company data with normalized lead data
// Input: Previous node outputs (prepared lead + enrichment API response)
// Output: Complete normalized lead object ready for decision logic

const enrichmentData = JSON.parse($json.data || '{}');
const originalLead = $items(0).json;

return [
  {
    json: {
      ...originalLead,
      normalized_data: {
        name: originalLead.input.name,
        email: originalLead.input.email,
        company: originalLead.input.company,
        company_size: enrichmentData.company_size || null,
        industry: enrichmentData.industry || null,
        message: originalLead.input.message,
        message_length: originalLead.input.message.length,
        ready_for_decision: true,
        normalized_at: new Date().toISOString()
      },
      enrichment_source: 'company_insights_api'
    }
  }
];

