parameters.functionCode:
// PARSE AI CLASSIFICATION RESPONSE
// Extracts JSON from AI response and validates structure
// Input: OpenAI node output (raw text or JSON)
// Output: Parsed classification with decision metadata

try {
  const classification = JSON.parse($json.data);

  return [
    {
      json: {
        ...$items(0).json,
        decision: {
          warmth: classification.warmth || 'Unknown',
          confidence: classification.confidence || 0,
          fit_score: classification.fit_score || 0,
          reasoning: classification.reasoning || '',
          key_signals: classification.key_signals || [],
          made_at: new Date().toISOString(),
          model: 'gpt-4-turbo'
        }
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        ...$items(0).json,
        decision: {
          warmth: 'Unknown',
          confidence: 0,
          fit_score: 0,
          reasoning: `Error parsing AI response: ${error.message}`,
          needs_manual_review: true,
          error_at: new Date().toISOString()
        }
      }
    }
  ];
}

